from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Handle edge case: return empty dict if no search results
    if not search_results:
        return {}

    # Initialize dictionary to accumulate grouped data
    groups = defaultdict(lambda: {'scores': [], 'count': 0})

    # Pre-accumulate necessary data during grouping
    for result in search_results:
        # Extract metadata value for group_by_field
        group_value = result.metadata.get(group_by_field)

        # Handle missing group_by_field values by assigning to 'unknown' group
        if group_value is None:
            group_value = 'unknown'

        group_data = groups[group_value]

        # Accumulate data for aggregation
        group_data['scores'].append(result.score)
        group_data['count'] += 1

        # Accumulate other metadata fields for potential aggregation
        for field, value in result.metadata.items():
            if field not in group_data:
                group_data[field] = []
            group_data[field].append(value)

    # Apply aggregation functions
    aggregated_results = {}
    default_funcs = {
        'count': lambda x: len(x),
        'avg_score': lambda x: sum(x) / len(x) if x else 0,
        'max_score': lambda x: max(x) if x else 0,
        'min_score': lambda x: min(x) if x else 0
    }

    for group_value, group_data in groups.items():
        # Use custom aggregation functions if provided, otherwise default
        funcs_to_apply = aggregation_funcs or default_funcs

        aggregated_stats = {}
        for stat_name, agg_func in funcs_to_apply.items():
            if stat_name in group_data and group_data[stat_name]:
                try:
                    aggregated_stats[stat_name] = agg_func(group_data[stat_name])
                except (ValueError, ZeroDivisionError):
                    aggregated_stats[stat_name] = None

        # Always include count and score statistics
        if 'count' not in aggregated_stats:
            aggregated_stats['count'] = group_data['count']
        if 'scores' in group_data and group_data['scores']:
            aggregated_stats['avg_score'] = default_funcs['avg_score'](group_data['scores'])
            aggregated_stats['max_score'] = default_funcs['max_score'](group_data['scores'])
            aggregated_stats['min_score'] = default_funcs['min_score'](group_data['scores'])

        aggregated_results[group_value] = aggregated_stats

    return aggregated_results

